  2958 | 
  2959 |   // (X + C2) >s C --> X <u (SMAX - C) (if C == C2 - 1)
  2960 |   if (Pred == CmpInst::ICMP_SGT && C == *C2 - 1)
  2961 |     return new ICmpInst(ICmpInst::ICMP_ULT, X, ConstantInt::get(Ty, SMax - C));
  2962 | 
  2963 |   // (X + C2) <s C --> X >u (C ^ SMAX) (if C == C2)
